"use client";

import { type BreadcrumbsProps, Breadcrumbs as BreadcrumbsRoot } from "./breadcrumbs";
import { BreadcrumbsEllipsis, type BreadcrumbsEllipsisProps } from "./breadcrumbs-ellipsis";
import { BreadcrumbsItem, type BreadcrumbsItemProps } from "./breadcrumbs-item";
import {
  BreadcrumbsLink,
  type BreadcrumbsLinkProps,
  type BreadcrumbsLinkRenderProps,
} from "./breadcrumbs-link";

/** Root container (nav + ol). Accepts separator prop. */
const Breadcrumbs = Object.assign(BreadcrumbsRoot, {
  Item: BreadcrumbsItem,
  Link: BreadcrumbsLink,
  Ellipsis: BreadcrumbsEllipsis,
});

export { Breadcrumbs, type BreadcrumbsProps };
export { BreadcrumbsEllipsis, type BreadcrumbsEllipsisProps };
export { BreadcrumbsItem, type BreadcrumbsItemProps };
export { BreadcrumbsLink, type BreadcrumbsLinkProps, type BreadcrumbsLinkRenderProps };

"use client";

import {
  Children,
  type ComponentPropsWithRef,
  cloneElement,
  Fragment,
  isValidElement,
  type ReactElement,
  type ReactNode,
  useMemo,
} from "react";
import { cn } from "@/lib/utils";
import { BreadcrumbsContext } from "./breadcrumbs-context";
import { BreadcrumbsItem, type BreadcrumbsItemProps } from "./breadcrumbs-item";

/** Props for breadcrumbs. */
export interface BreadcrumbsProps extends ComponentPropsWithRef<"nav"> {
  /** Separator rendered between items. Pass null to omit. */
  separator?: ReactNode;
}

function isBreadcrumbsItemElement(child: ReactNode): child is ReactElement<BreadcrumbsItemProps> {
  return isValidElement<BreadcrumbsItemProps>(child) && child.type === BreadcrumbsItem;
}

function flattenFragments(children: ReactNode, parentKey?: string): ReactNode[] {
  return Children.toArray(children).flatMap((child, index) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return [child];
    const childKey = child.key === null ? String(index) : String(child.key);
    const composedKey = parentKey === undefined ? childKey : `${parentKey}/${childKey}`;
    if (child.type === Fragment) return flattenFragments(child.props.children, composedKey);
    return parentKey === undefined ? [child] : [cloneElement(child, { key: composedKey })];
  });
}

function resolveCurrentItem(children: ReactNode): ReactNode {
  const childArray = flattenFragments(children);
  const hasCurrentItem = childArray.some(
    (child) => isBreadcrumbsItemElement(child) && child.props.current,
  );
  const lastItemIndex = hasCurrentItem ? -1 : childArray.findLastIndex(isBreadcrumbsItemElement);

  if (lastItemIndex < 0) return childArray;

  return childArray.map((child, index) =>
    index === lastItemIndex && isBreadcrumbsItemElement(child)
      ? cloneElement(child, { current: true })
      : child,
  );
}

/** Root container (nav + ol). Accepts separator prop. */
export function Breadcrumbs({
  separator = "/",
  className,
  children,
  ref,
  ...props
}: BreadcrumbsProps) {
  const contextValue = useMemo(() => ({ separator }), [separator]);
  const resolvedChildren = resolveCurrentItem(children);

  return (
    <BreadcrumbsContext value={contextValue}>
      <nav
        ref={ref}
        data-slot="breadcrumbs"
        aria-label="Breadcrumb"
        className={cn("text-xs text-muted-foreground", className)}
        {...props}
      >
        {/* biome-ignore lint/a11y/useSemanticElements: this already is an <ol>; the explicit role="list" below restores list semantics that Tailwind preflight strips, and Biome should not suggest swapping the element. */}
        <ol
          // biome-ignore lint/a11y/noRedundantRoles: Tailwind preflight sets list-style:none on <ol>, which drops list semantics in Safari/VoiceOver; role="list" restores them.
          role="list"
          className="m-0 flex list-none flex-wrap items-center gap-1.5 p-0"
        >
          {resolvedChildren}
        </ol>
      </nav>
    </BreadcrumbsContext>
  );
}

"use client";

import { createContext, type ReactNode, useContext } from "react";

/** Context value shared by breadcrumbs. */
interface BreadcrumbsContextValue {
  /** Separator rendered between items. Pass null to omit. */
  separator: ReactNode;
  /** Marks the item as current. */
  current?: boolean;
}

/** React context backing breadcrumbs. */
const BreadcrumbsContext = createContext<BreadcrumbsContextValue | undefined>(undefined);

/** Reads the breadcrumbs context. */
export function useBreadcrumbsContext(): BreadcrumbsContextValue {
  const ctx = useContext(BreadcrumbsContext);
  if (ctx === undefined) throw new Error("Breadcrumbs parts must be used within a Breadcrumbs");
  return ctx;
}

export { BreadcrumbsContext };

"use client";

import { Children, type ComponentPropsWithRef, isValidElement, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { BreadcrumbsContext, useBreadcrumbsContext } from "./breadcrumbs-context";
import { BreadcrumbsLink } from "./breadcrumbs-link";

/** Props for breadcrumbs item. */
export interface BreadcrumbsItemProps extends ComponentPropsWithRef<"li"> {
  /**
   * Marks the item as the current page. Auto-applied to the last item when no item explicitly
   * sets it. Adds aria-current="page" and bold styling.
   */
  current?: boolean;
}

function containsBreadcrumbsLink(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === BreadcrumbsLink) return true;
    return containsBreadcrumbsLink(child.props.children);
  });
}

/** List item - auto-inserts separator. Use current prop to mark the current page. */
export function BreadcrumbsItem({
  current,
  className,
  children,
  ref,
  ...props
}: BreadcrumbsItemProps) {
  const { separator } = useBreadcrumbsContext();
  const itemContext = { separator, current };
  const itemOwnsCurrent = current && !containsBreadcrumbsLink(children);

  return (
    <>
      {separator != null && (
        <li
          role="presentation"
          aria-hidden="true"
          className="[&>svg]:size-3.5 text-muted-foreground/40 first:hidden"
        >
          {separator}
        </li>
      )}
      <BreadcrumbsContext value={itemContext}>
        <li
          ref={ref}
          className={cn(
            "inline-flex items-center gap-1.5",
            current && "font-bold text-foreground",
            className,
          )}
          {...props}
          aria-current={itemOwnsCurrent ? "page" : props["aria-current"]}
        >
          {children}
        </li>
      </BreadcrumbsContext>
    </>
  );
}

"use client";

import type { AnchorHTMLAttributes, ReactNode, Ref } from "react";
import { cn } from "@/lib/utils";
import { useBreadcrumbsContext } from "./breadcrumbs-context";

/** Props for breadcrumbs link render. */
export type BreadcrumbsLinkRenderProps = AnchorHTMLAttributes<HTMLAnchorElement> & {
  ref: Ref<HTMLAnchorElement>;
  className: string;
  "data-slot": "breadcrumbs-link";
};

/** Props for breadcrumbs link. */
export interface BreadcrumbsLinkProps
  extends Omit<AnchorHTMLAttributes<HTMLAnchorElement>, "children"> {
  /**
   * Link label, or a render function that receives ref, className, aria-current, and remaining
   * anchor props.
   */
  children: ReactNode | ((props: BreadcrumbsLinkRenderProps) => ReactNode);
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLAnchorElement>;
}

/** Navigation link. Supports render-prop for custom components. */
export function BreadcrumbsLink({ children, className, ref, ...props }: BreadcrumbsLinkProps) {
  const { current } = useBreadcrumbsContext();
  const renderProps: BreadcrumbsLinkRenderProps = {
    ref: ref ?? null,
    className: cn(
      "transition-colors hover:text-foreground hover:underline hover:underline-offset-2",
      className,
    ),
    "aria-current": current ? "page" : undefined,
    "data-slot": "breadcrumbs-link",
    ...props,
  };

  if (typeof children === "function") return <>{children(renderProps)}</>;

  return <a {...renderProps}>{children}</a>;
}

"use client";

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

/** Props for breadcrumbs ellipsis. */
export interface BreadcrumbsEllipsisProps extends ComponentPropsWithRef<"span"> {
  /** Screen-reader text announcing collapsed levels. Defaults to "More". */
  label?: string;
}

/** Collapsed items placeholder. */
export function BreadcrumbsEllipsis({
  children = "...",
  className,
  label = "More",
  ref,
  ...props
}: BreadcrumbsEllipsisProps) {
  return (
    <span ref={ref} className={cn("flex size-5 items-center justify-center", className)} {...props}>
      <span aria-hidden="true">{children}</span>
      <span className="sr-only">{label}</span>
    </span>
  );
}
